const jobs = items[0].json.jobs || [];

return jobs.map(job => ({
  json: {
    title: job.title,
    company: job.company_name,
    location: job.candidate_required_location,
    category: job.category,
    job_type: job.job_type,
    url: job.url,
    source: "Remotive"
  }
}));

return items
  .map(item => ({
    json: {
      title: item.json.title || "",
      company: "",
      location: "Remote",
      category: "Remote",
      job_type: "remote",
      url: item.json.link || "",
      source: "We Work Remotely"
    }
  }))
  .filter(item => {
    const text = (item.json.title || "").toLowerCase();

    const isRelevant =
      text.includes("data") ||
      text.includes("analyst") ||
      text.includes("analytics") ||
      text.includes("data science") ||
      text.includes("machine learning") ||
      text.includes("business intelligence");

    const isStudentLike =
      text.includes("intern") ||
      text.includes("student") ||
      text.includes("junior") ||
      text.includes("working student") ||
      text.includes("werkstudent");

    return isRelevant || isStudentLike;
  });

return items.filter(item => {
  const text = `
    ${item.json.title || ""}
    ${item.json.category || ""}
    ${item.json.job_type || ""}
    ${item.json.location || ""}
  `.toLowerCase();

  const isData =
    text.includes("data") ||
    text.includes("analyst") ||
    text.includes("analytics") ||
    text.includes("data science") ||
    text.includes("machine learning") ||
    text.includes("business intelligence");

  const isLocationOk =
    text.includes("berlin") ||
    text.includes("remote") ||
    text.includes("worldwide") ||
    text.includes("europe") ||
    text.includes("germany");

  return isData && isLocationOk;
});

return items.map(item => {
  const text = `
    ${item.json.title || ""}
    ${item.json.category || ""}
    ${item.json.job_type || ""}
    ${item.json.location || ""}
  `.toLowerCase();

  let score = 0;

  if (text.includes("werkstudent")) score += 4;
  if (text.includes("working student")) score += 4;
  if (text.includes("student")) score += 2;
  if (text.includes("intern")) score += 2;
  if (text.includes("junior")) score += 1;
  if (text.includes("part")) score += 1;

  if (text.includes("data analyst")) score += 4;
  if (text.includes("analytics")) score += 3;
  if (text.includes("data science")) score += 3;
  if (text.includes("machine learning")) score += 2;
  if (text.includes("business intelligence")) score += 2;

  if (text.includes("berlin")) score += 2;
  if (text.includes("remote")) score += 2;

  return {
    json: {
      ...item.json,
      score
    }
  };
});

return items.map(item => {
  const clean = (value, max = 300) => {
    if (value === null || value === undefined) return "";
    return String(value).replace(/\s+/g, " ").trim().slice(0, max);
  };

  return {
    json: {
      title: clean(item.json.title, 200),
      company: clean(item.json.company, 150),
      location: clean(item.json.location, 100),
      category: clean(item.json.category, 100),
      job_type: clean(item.json.job_type, 50),
      url: clean(item.json.url, 500),
      source: clean(item.json.source, 50),
      score: item.json.score || 0
    }
  };
});

const unique = [];
const seen = new Set();

for (const item of items) {
  if (!seen.has(item.json.link)) {
    seen.add(item.json.link);
    unique.push(item);
  }
}

return unique;
